// Parse Kibana alert → TheHive case payload + observable list
const alert = $input.first().json.body || $input.first().json;
const ruleName = alert.rule?.name || 'Unknown rule';
const severity = (alert.rule?.severity || 'medium').toLowerCase();
const sevMap = { low: 1, medium: 2, high: 3, critical: 4 };

// Extract candidate observables (auto-extract for B1)
const observables = [];
if (alert['url.original']) observables.push({ dataType: 'url', data: alert['url.original'], message: 'URL probed' });
if (alert['source.ip']) observables.push({ dataType: 'ip', data: alert['source.ip'], message: 'Source IP' });
else if (alert['source.address']) observables.push({ dataType: 'ip', data: alert['source.address'], message: 'Source address' });
if (alert['user_agent.original']) observables.push({ dataType: 'user-agent', data: alert['user_agent.original'], message: 'User-Agent' });

// Auto-pick Cortex analyzer per observable type (B2)
const analyzerMap = {
  'ip': 'AbuseIPDB_2_0',
  'url': 'VirusTotal_GetReport_3_1',
  'domain': 'VirusTotal_GetReport_3_1',
  'hash': 'VirusTotal_GetReport_3_1'
};

return [{
  json: {
    casePayload: {
      title: `[VN-SOC] ${ruleName}`,
      description: `Auto-created from Kibana detection rule.\n\nRule: ${ruleName}\nSeverity: ${severity}\nTimestamp: ${alert['@timestamp'] || new Date().toISOString()}\nML score: ${JSON.stringify(alert.ml || {})}\nSource event (truncated):\n${JSON.stringify(alert, null, 2).substring(0, 1500)}`,
      severity: sevMap[severity] || 2,
      tlp: 2,
      pap: 2,
      tags: ['vn-soc-lab', 'auto-created', `severity-${severity}`],
      sourceRef: alert._alert_id || `vnsoc-${Date.now()}`
    },
    observables: observables,
    analyzerMap: analyzerMap
  }
}];

// Pair created case with observables list (fan-out one item per observable)
const caseData = $input.first().json;
const parseData = $('Parse Alert → Case + Observables').first().json;
return parseData.observables.map(obs => ({
  json: {
    caseId: caseData._id,
    caseNumber: caseData.number,
    observable: obs,
    analyzerId: parseData.analyzerMap[obs.dataType] || null
  }
}));

// Extract artifact id from v0 response, attach analyzerId for Cortex run
const raw = $input.first().json;
const arr = Array.isArray(raw) ? raw : [raw];
const obs = arr[0] || {};
const fanData = $('Fan-out observables').first().json;
return [{
  json: {
    artifactId: obs._id || obs.id,
    caseId: fanData.caseId,
    analyzerId: fanData.analyzerId
  }
}];
